const e="matematicas",a=JSON.parse(`[{"id":"mat-001","front":"¿Qué significa que dos vectores del espacio sean linealmente independientes?","back":"Que ninguno puede expresarse como combinación lineal del otro. Equivale a que la única solución de λu + μv = 0 sea λ = μ = 0.","topic":"Álgebra lineal","difficulty":1,"fromOrientaciones":true},{"id":"mat-002","front":"¿Qué es una base de un espacio vectorial?","back":"Es un conjunto de vectores linealmente independientes que genera todo el espacio. Cualquier vector del espacio se escribe como combinación lineal de ellos.","topic":"Álgebra lineal","difficulty":1,"fromOrientaciones":true},{"id":"mat-003","front":"¿Cuándo una matriz cuadrada es invertible?","back":"Cuando su determinante es distinto de 0. En ese caso existe A⁻¹ y además rg(A) = n.","topic":"Álgebra lineal","difficulty":1,"fromOrientaciones":true},{"id":"mat-004","front":"¿Cuál es la fórmula del determinante de una matriz 2x2?","back":"Si A = ((a,b),(c,d)), entonces det(A) = ad - bc. Si vale 0, la matriz no es invertible.","topic":"Álgebra lineal","difficulty":1,"fromOrientaciones":true},{"id":"mat-005","front":"¿Qué indica que el determinante de una matriz sea 0?","back":"Que la matriz no es regular, no tiene inversa y sus filas o columnas son linealmente dependientes.","topic":"Álgebra lineal","difficulty":1,"fromOrientaciones":true},{"id":"mat-006","front":"¿Qué es la matriz traspuesta de una matriz A?","back":"Es la matriz que se obtiene intercambiando filas por columnas. Se denota por Aᵗ.","topic":"Álgebra lineal","difficulty":1,"fromOrientaciones":true},{"id":"mat-007","front":"¿Cuándo una matriz es simétrica?","back":"Cuando coincide con su traspuesta: A = Aᵗ. Solo puede ocurrir en matrices cuadradas.","topic":"Álgebra lineal","difficulty":1,"fromOrientaciones":true},{"id":"mat-008","front":"¿Cuándo una matriz es antisimétrica?","back":"Cuando Aᵗ = -A. En una matriz antisimétrica los elementos de la diagonal principal son 0.","topic":"Álgebra lineal","difficulty":2,"fromOrientaciones":true},{"id":"mat-009","front":"¿Cómo se suman dos matrices del mismo orden?","back":"Se suman elemento a elemento. Solo se pueden sumar si tienen igual número de filas y columnas.","topic":"Álgebra lineal","difficulty":1,"fromOrientaciones":true},{"id":"mat-010","front":"¿Qué condición debe cumplirse para poder multiplicar dos matrices A·B?","back":"El número de columnas de A debe coincidir con el número de filas de B. El resultado tiene las filas de A y las columnas de B.","topic":"Álgebra lineal","difficulty":1,"fromOrientaciones":true},{"id":"mat-011","front":"¿Es conmutativo el producto de matrices?","back":"No, en general AB ≠ BA. Por eso hay que respetar el orden al multiplicar.","topic":"Álgebra lineal","difficulty":1,"fromOrientaciones":true},{"id":"mat-012","front":"¿Qué pasos hay que seguir para calcular el rango de una matriz por Gauss?","back":"Se escalona la matriz mediante operaciones elementales y se cuentan las filas no nulas. Ese número es el rango.","topic":"Álgebra lineal","difficulty":2,"fromOrientaciones":true},{"id":"mat-013","front":"¿Cómo se calcula la inversa de una matriz 2x2?","back":"Si A = ((a,b),(c,d)) y ad-bc ≠ 0, entonces A⁻¹ = 1/(ad-bc) · ((d,-b),(-c,a)).","topic":"Álgebra lineal","difficulty":2,"fromOrientaciones":true},{"id":"mat-014","front":"¿Qué significa que una potencia de una matriz sea cíclica?","back":"Que las potencias repiten un patrón, por ejemplo A² = I o A³ = A. Esto permite calcular Aⁿ sin multiplicar muchas veces.","topic":"Álgebra lineal","difficulty":2,"fromOrientaciones":true},{"id":"mat-015","front":"¿Cómo se expresa un sistema de ecuaciones lineales en forma matricial?","back":"Como AX = B, donde A es la matriz de coeficientes, X el vector incógnita y B el vector de términos independientes.","topic":"Sistemas lineales","difficulty":1,"fromOrientaciones":true},{"id":"mat-016","front":"¿Qué es la matriz ampliada de un sistema lineal?","back":"Es la matriz que se obtiene añadiendo a la matriz de coeficientes la columna de términos independientes: (A|B).","topic":"Sistemas lineales","difficulty":1,"fromOrientaciones":true},{"id":"mat-017","front":"¿Qué diferencia hay entre sistema compatible determinado, compatible indeterminado e incompatible?","back":"El primero tiene una única solución, el segundo infinitas soluciones y el tercero no tiene solución.","topic":"Sistemas lineales","difficulty":1,"fromOrientaciones":true},{"id":"mat-018","front":"¿Qué dice el teorema de Rouché-Frobenius?","back":"Un sistema es compatible si rg(A) = rg(A|B). Si además ese rango coincide con el número de incógnitas, la solución es única.","topic":"Sistemas lineales","difficulty":2,"fromOrientaciones":true},{"id":"mat-019","front":"¿Cuándo se puede aplicar la regla de Cramer para resolver un sistema?","back":"Cuando el sistema tiene tantas ecuaciones como incógnitas y det(A) ≠ 0. Entonces la solución es única.","topic":"Sistemas lineales","difficulty":2,"fromOrientaciones":true},{"id":"mat-020","front":"¿Cómo se resuelve una ecuación matricial del tipo AX = B si A es invertible?","back":"Se multiplica por A⁻¹ a la izquierda: X = A⁻¹B. Antes hay que comprobar que A tenga inversa.","topic":"Álgebra lineal","difficulty":2,"fromOrientaciones":true},{"id":"mat-021","front":"¿Qué es el producto escalar de dos vectores?","back":"Es un número real: u·v = |u||v|cosθ. También se calcula sumando los productos de sus componentes.","topic":"Vectores y geometría","difficulty":1,"fromOrientaciones":true},{"id":"mat-022","front":"¿Cómo se decide si dos vectores son perpendiculares usando el producto escalar?","back":"Son perpendiculares si u·v = 0. Eso equivale a que formen un ángulo de 90°.","topic":"Vectores y geometría","difficulty":1,"fromOrientaciones":true},{"id":"mat-023","front":"¿Qué es el producto vectorial de dos vectores del espacio?","back":"Es un vector perpendicular a ambos. Su módulo es |u×v| = |u||v|senθ.","topic":"Vectores y geometría","difficulty":2,"fromOrientaciones":true},{"id":"mat-024","front":"¿Para qué sirve el producto vectorial en geometría?","back":"Sirve para obtener un vector normal a un plano y para calcular áreas, como la de un paralelogramo: |u×v|.","topic":"Vectores y geometría","difficulty":2,"fromOrientaciones":true},{"id":"mat-025","front":"¿Qué es el producto mixto de tres vectores?","back":"Es u·(v×w). Su valor absoluto da el volumen del paralelepípedo formado por los tres vectores.","topic":"Vectores y geometría","difficulty":2,"fromOrientaciones":true},{"id":"mat-026","front":"¿Cómo se calcula el área de un triángulo en el espacio con dos vectores?","back":"Si los vectores de sus lados son u y v, el área es |u×v|/2.","topic":"Geometría del espacio","difficulty":2,"fromOrientaciones":true},{"id":"mat-027","front":"¿Qué información aporta un vector normal de un plano?","back":"Indica la dirección perpendicular al plano. Con él se escribe la ecuación general: ax + by + cz + d = 0.","topic":"Geometría del espacio","difficulty":1,"fromOrientaciones":true},{"id":"mat-028","front":"¿Cuál es la ecuación general de un plano?","back":"ax + by + cz + d = 0, donde (a,b,c) es un vector normal al plano.","topic":"Geometría del espacio","difficulty":1,"fromOrientaciones":true},{"id":"mat-029","front":"¿Cómo se escribe la ecuación vectorial de una recta en el espacio?","back":"r: (x,y,z) = P + λv, donde P es un punto de la recta y v es un vector director.","topic":"Geometría del espacio","difficulty":1,"fromOrientaciones":true},{"id":"mat-030","front":"¿Qué significa que dos rectas del espacio se crucen?","back":"Que no son paralelas ni secantes. No se cortan y no están contenidas en un mismo plano.","topic":"Geometría del espacio","difficulty":2,"fromOrientaciones":true},{"id":"mat-031","front":"¿Cómo se estudia la posición relativa de dos rectas en el espacio?","back":"Se comparan sus vectores directores y se resuelve el sistema de sus ecuaciones. Pueden ser coincidentes, paralelas, secantes o cruzadas.","topic":"Geometría del espacio","difficulty":2,"fromOrientaciones":true},{"id":"mat-032","front":"¿Cómo se calcula la distancia entre dos puntos del espacio?","back":"Si A(x1,y1,z1) y B(x2,y2,z2), entonces d = √[(x2-x1)² + (y2-y1)² + (z2-z1)²].","topic":"Geometría métrica","difficulty":1,"fromOrientaciones":true},{"id":"mat-033","front":"¿Cómo se calcula la distancia de un punto a un plano?","back":"Si el plano es ax+by+cz+d=0 y el punto es P(x0,y0,z0), entonces d = |ax0+by0+cz0+d| / √(a²+b²+c²).","topic":"Geometría métrica","difficulty":2,"fromOrientaciones":true},{"id":"mat-034","front":"¿Qué condición deben cumplir dos planos para ser paralelos?","back":"Sus vectores normales deben ser proporcionales. Si además comparten un punto, entonces coinciden.","topic":"Geometría del espacio","difficulty":1,"fromOrientaciones":true},{"id":"mat-035","front":"¿Cómo se calcula el ángulo entre dos rectas usando sus vectores directores?","back":"Se usa cosθ = |u·v| / (|u||v|). El valor absoluto da el ángulo agudo entre ambas.","topic":"Geometría métrica","difficulty":2,"fromOrientaciones":true},{"id":"mat-036","front":"¿Cómo se obtiene el plano que contiene una recta y un punto exterior a ella?","back":"Se toma un punto de la recta y dos vectores del plano: el director de la recta y el que une ese punto con el punto exterior. Con su producto vectorial se halla el normal.","topic":"Geometría del espacio","difficulty":3,"fromOrientaciones":true},{"id":"mat-037","front":"¿Qué es el límite de una función en un punto?","back":"Es el valor al que se aproxima f(x) cuando x se acerca a ese punto. No exige que la función esté definida allí.","topic":"Límites y continuidad","difficulty":1,"fromOrientaciones":true},{"id":"mat-038","front":"¿Qué diferencia hay entre límite finito y límite infinito?","back":"El límite es finito si f(x) se aproxima a un número real; es infinito si crece o decrece sin cota al acercarse al punto.","topic":"Límites y continuidad","difficulty":1,"fromOrientaciones":true},{"id":"mat-039","front":"¿Cuándo existe una asíntota vertical en x = a?","back":"Cuando al aproximarse x a a, la función tiende a +∞ o -∞ por alguno de los lados.","topic":"Límites y continuidad","difficulty":1,"fromOrientaciones":true},{"id":"mat-040","front":"¿Cuándo existe una asíntota horizontal?","back":"Cuando lim x→±∞ f(x) = L, con L real. Entonces y = L es la asíntota horizontal.","topic":"Límites y continuidad","difficulty":1,"fromOrientaciones":true},{"id":"mat-041","front":"¿Cuándo existe una asíntota oblicua y cómo se calcula?","back":"Existe si lim x→∞ [f(x) - (mx+n)] = 0. Se calcula m = lim f(x)/x y luego n = lim [f(x)-mx].","topic":"Límites y continuidad","difficulty":3,"fromOrientaciones":true},{"id":"mat-042","front":"¿Qué significa que una función sea continua en un punto x = a?","back":"Que existe f(a), existe lim x→a f(x) y ambos coinciden. No hay salto ni hueco en ese punto.","topic":"Límites y continuidad","difficulty":1,"fromOrientaciones":true},{"id":"mat-043","front":"¿Qué es una discontinuidad evitable?","back":"Es una discontinuidad con límite finito en el punto, pero la función no está definida allí o toma otro valor distinto.","topic":"Límites y continuidad","difficulty":1,"fromOrientaciones":true},{"id":"mat-044","front":"¿Qué es una discontinuidad de salto finito?","back":"Ocurre cuando existen los límites laterales en el punto, son finitos, pero distintos entre sí.","topic":"Límites y continuidad","difficulty":1,"fromOrientaciones":true},{"id":"mat-045","front":"¿Qué relación existe entre continuidad y derivabilidad?","back":"Si una función es derivable en un punto, entonces es continua en él. La recíproca no siempre es cierta.","topic":"Cálculo diferencial","difficulty":2,"fromOrientaciones":true},{"id":"mat-046","front":"¿Qué es la derivada de una función en un punto?","back":"Es la pendiente de la recta tangente en ese punto y la tasa de variación instantánea de la función.","topic":"Cálculo diferencial","difficulty":1,"fromOrientaciones":true},{"id":"mat-047","front":"¿Qué diferencia hay entre f'(x) y f'(a)?","back":"f'(x) es la función derivada; f'(a) es el valor concreto de esa derivada en el punto x = a.","topic":"Cálculo diferencial","difficulty":1,"fromOrientaciones":true},{"id":"mat-048","front":"¿Cuál es la regla para derivar una suma de funciones?","back":"La derivada de una suma es la suma de las derivadas: (f+g)' = f' + g'.","topic":"Cálculo diferencial","difficulty":1,"fromOrientaciones":true},{"id":"mat-049","front":"¿Cuál es la regla para derivar un producto de funciones?","back":"Regla del producto: (f·g)' = f'·g + f·g'. Hay que derivar una y dejar la otra, y luego al revés.","topic":"Cálculo diferencial","difficulty":2,"fromOrientaciones":true},{"id":"mat-050","front":"¿Cuál es la regla para derivar un cociente de funciones?","back":"Regla del cociente: (f/g)' = (f'g - fg') / g², siempre que g ≠ 0.","topic":"Cálculo diferencial","difficulty":2,"fromOrientaciones":true},{"id":"mat-051","front":"¿Qué dice la regla de la cadena?","back":"Si y = f(g(x)), entonces y' = f'(g(x))·g'(x). Se deriva la exterior y se multiplica por la derivada de la interior.","topic":"Cálculo diferencial","difficulty":2,"fromOrientaciones":true},{"id":"mat-052","front":"¿Qué son las derivadas laterales?","back":"Son las derivadas calculadas aproximándose al punto solo por la izquierda o solo por la derecha. Deben coincidir para que haya derivada.","topic":"Cálculo diferencial","difficulty":2,"fromOrientaciones":true},{"id":"mat-053","front":"¿Cómo se sabe si una función crece o decrece usando la derivada?","back":"Si f'(x) > 0 la función crece; si f'(x) < 0 decrece. Se estudia el signo de la derivada por intervalos.","topic":"Cálculo diferencial","difficulty":1,"fromOrientaciones":true},{"id":"mat-054","front":"¿Qué es un punto crítico de una función?","back":"Es un punto donde f'(x)=0 o donde la derivada no existe. En ellos puede haber máximos, mínimos o nada.","topic":"Cálculo diferencial","difficulty":2,"fromOrientaciones":true},{"id":"mat-055","front":"¿Qué condición debe cumplir f(x) para tener un máximo relativo en x = a?","back":"Normalmente f'(a)=0 y la derivada cambia de positiva a negativa. También puede comprobarse con f''(a)<0 si existe.","topic":"Cálculo diferencial","difficulty":2,"fromOrientaciones":true},{"id":"mat-056","front":"¿Qué condición debe cumplir f(x) para tener un mínimo relativo en x = a?","back":"Normalmente f'(a)=0 y la derivada cambia de negativa a positiva. Si existe f''(a), basta con que sea positiva.","topic":"Cálculo diferencial","difficulty":2,"fromOrientaciones":true},{"id":"mat-057","front":"¿Qué indica el signo de la segunda derivada en un intervalo?","back":"Si f''(x) > 0 la función es convexa; si f''(x) < 0 es cóncava.","topic":"Cálculo diferencial","difficulty":1,"fromOrientaciones":true},{"id":"mat-058","front":"¿Qué es un punto de inflexión?","back":"Es un punto donde cambia la concavidad de la función. Suele ocurrir cuando f'' cambia de signo.","topic":"Cálculo diferencial","difficulty":2,"fromOrientaciones":true},{"id":"mat-059","front":"¿Cómo se calcula la ecuación de la recta tangente a y = f(x) en x = a?","back":"Primero se halla f(a) y f'(a). Luego: y - f(a) = f'(a)(x - a).","topic":"Cálculo diferencial","difficulty":2,"fromOrientaciones":true},{"id":"mat-060","front":"¿Cómo se calcula la ecuación de la recta normal a una curva en un punto?","back":"Su pendiente es la opuesta inversa de la tangente: m_n = -1/f'(a), si f'(a) ≠ 0. Luego se usa la ecuación punto-pendiente.","topic":"Cálculo diferencial","difficulty":2,"fromOrientaciones":true},{"id":"mat-061","front":"¿Cuándo se puede aplicar la regla de L’Hôpital?","back":"Cuando un límite de cociente da una indeterminación 0/0 o ∞/∞. Se derivan numerador y denominador y se vuelve a calcular el límite.","topic":"Límites y continuidad","difficulty":3,"fromOrientaciones":true},{"id":"mat-062","front":"¿Qué elementos básicos deben aparecer al representar aproximadamente una función?","back":"Dominio, cortes con ejes, simetrías, periodicidad, asíntotas, crecimiento, extremos, concavidad, convexidad y puntos de inflexión.","topic":"Representación de funciones","difficulty":2,"fromOrientaciones":true},{"id":"mat-063","front":"¿Qué significa que una función sea par?","back":"Que f(-x)=f(x). Su gráfica es simétrica respecto del eje Y.","topic":"Representación de funciones","difficulty":1,"fromOrientaciones":true},{"id":"mat-064","front":"¿Qué significa que una función sea impar?","back":"Que f(-x)=-f(x). Su gráfica es simétrica respecto del origen.","topic":"Representación de funciones","difficulty":1,"fromOrientaciones":true},{"id":"mat-065","front":"¿Cómo se resuelve un problema de optimización con derivadas?","back":"Se expresa la magnitud a optimizar como función, se deriva, se buscan puntos críticos y se decide cuál da el valor máximo o mínimo en el contexto.","topic":"Optimización","difficulty":2,"fromOrientaciones":true},{"id":"mat-066","front":"¿Qué es una primitiva de una función?","back":"Es una función F tal que F'(x)=f(x). También se llama integral indefinida de f.","topic":"Cálculo integral","difficulty":1,"fromOrientaciones":true},{"id":"mat-067","front":"¿Qué relación existe entre dos primitivas de una misma función?","back":"Se diferencian en una constante. Si F'(x)=f(x) y G'(x)=f(x), entonces G(x)=F(x)+C.","topic":"Cálculo integral","difficulty":1,"fromOrientaciones":true},{"id":"mat-068","front":"¿Cómo se determina una primitiva concreta si se conoce que pasa por un punto?","back":"Se halla la familia F(x)+C y se sustituye el punto dado para calcular la constante C.","topic":"Cálculo integral","difficulty":2,"fromOrientaciones":true},{"id":"mat-069","front":"¿Qué es la integral definida desde a hasta b?","back":"Es el área con signo bajo la curva entre x=a y x=b. Se calcula usando primitivas.","topic":"Cálculo integral","difficulty":1,"fromOrientaciones":true},{"id":"mat-070","front":"¿Qué dice la regla de Barrow?","back":"Si F es una primitiva de f, entonces ∫[a,b] f(x)dx = F(b) - F(a).","topic":"Cálculo integral","difficulty":1,"fromOrientaciones":true},{"id":"mat-071","front":"¿Cuál es la propiedad de linealidad de la integral?","back":"∫(af(x)+bg(x))dx = a∫f(x)dx + b∫g(x)dx. También vale en integrales definidas.","topic":"Cálculo integral","difficulty":2,"fromOrientaciones":true},{"id":"mat-072","front":"¿Cuál es la propiedad de aditividad respecto al intervalo de integración?","back":"Si c está entre a y b, entonces ∫[a,b]f(x)dx = ∫[a,c]f(x)dx + ∫[c,b]f(x)dx.","topic":"Cálculo integral","difficulty":2,"fromOrientaciones":true},{"id":"mat-073","front":"¿Qué pasos hay que seguir para resolver una integral por partes?","back":"Se eligen u y dv, se calcula du y v, y se aplica ∫u·dv = u·v - ∫v·du.","topic":"Cálculo integral","difficulty":2,"fromOrientaciones":true},{"id":"mat-074","front":"¿Qué pasos hay que seguir para resolver una integral por cambio de variable?","back":"Se hace una sustitución x→u, se deriva para cambiar dx y se reescribe toda la integral en la nueva variable.","topic":"Cálculo integral","difficulty":2,"fromOrientaciones":true},{"id":"mat-075","front":"¿Cómo se calcula el área encerrada entre dos curvas y = f(x) e y = g(x)?","back":"Se hallan los puntos de corte y se integra función superior menos inferior: A = ∫a,bdx.","topic":"Cálculo integral","difficulty":2,"fromOrientaciones":true},{"id":"mat-076","front":"¿Cómo se calcula el volumen de un sólido de revolución alrededor del eje OX?","back":"Si gira y=f(x)≥0 entre a y b, entonces V = π∫a,b²dx.","topic":"Cálculo integral","difficulty":3,"fromOrientaciones":true},{"id":"mat-077","front":"¿Qué es la probabilidad condicionada de A sabiendo B?","back":"Es P(A|B)=P(A∩B)/P(B), con P(B)>0. Mide la probabilidad de A cuando se sabe que B ha ocurrido.","topic":"Probabilidad","difficulty":1,"fromOrientaciones":true},{"id":"mat-078","front":"¿Cuándo dos sucesos A y B son independientes?","back":"Cuando P(A∩B)=P(A)·P(B). Equivale a que P(A|B)=P(A), si P(B)>0.","topic":"Probabilidad","difficulty":2,"fromOrientaciones":true},{"id":"mat-079","front":"¿Qué dicen las leyes de De Morgan para sucesos?","back":"El complementario de la unión es la intersección de los complementarios, y viceversa: (A∪B)ᶜ=Aᶜ∩Bᶜ y (A∩B)ᶜ=Aᶜ∪Bᶜ.","topic":"Probabilidad","difficulty":2,"fromOrientaciones":true},{"id":"mat-080","front":"¿Qué es el teorema de la probabilidad total?","back":"Si {B1,...,Bn} forma una partición, entonces P(A)=Σ P(A|Bi)·P(Bi). Permite calcular probabilidades globales a partir de casos.","topic":"Probabilidad","difficulty":2,"fromOrientaciones":true},{"id":"mat-081","front":"¿Qué es el teorema de Bayes y para qué sirve?","back":"Permite calcular P(B|A) a partir de P(A|B): P(B|A)=P(A|B)·P(B)/P(A). Sirve para actualizar probabilidades con nueva información.","topic":"Probabilidad","difficulty":2,"fromOrientaciones":true},{"id":"mat-082","front":"¿Qué es una variable aleatoria discreta?","back":"Es una variable que toma valores aislados, normalmente contables. A cada valor se le asigna una probabilidad.","topic":"Estadística y probabilidad","difficulty":1,"fromOrientaciones":true},{"id":"mat-083","front":"¿Qué es una variable aleatoria continua?","back":"Es una variable que puede tomar infinitos valores de un intervalo. Sus probabilidades se calculan sobre intervalos.","topic":"Estadística y probabilidad","difficulty":1,"fromOrientaciones":true},{"id":"mat-084","front":"¿Qué parámetros caracterizan una distribución de probabilidad?","back":"Los más habituales son la media y la desviación típica. Describen el centro y la dispersión de la distribución.","topic":"Estadística y probabilidad","difficulty":1,"fromOrientaciones":true},{"id":"mat-085","front":"¿Qué es una distribución binomial?","back":"Modeliza el número de éxitos en n ensayos independientes con probabilidad p de éxito en cada uno. Se denota B(n,p).","topic":"Distribuciones","difficulty":1,"fromOrientaciones":true},{"id":"mat-086","front":"¿Cuáles son los parámetros de una distribución binomial?","back":"n, que es el número de ensayos, y p, que es la probabilidad de éxito. También q=1-p es la probabilidad de fracaso.","topic":"Distribuciones","difficulty":1,"fromOrientaciones":true},{"id":"mat-087","front":"¿Cómo se calcula la probabilidad de exactamente k éxitos en una binomial?","back":"Se usa P(X=k)=C(n,k)·p^k·(1-p)^(n-k). Hace falta identificar bien n, k y p.","topic":"Distribuciones","difficulty":2,"fromOrientaciones":true},{"id":"mat-088","front":"¿Qué es una distribución normal?","back":"Es una distribución continua, simétrica y con forma de campana. Queda determinada por su media μ y su desviación típica σ.","topic":"Distribuciones","difficulty":1,"fromOrientaciones":true},{"id":"mat-089","front":"¿Cómo se tipifica una variable normal X~N(μ,σ)?","back":"Se transforma en Z=(X-μ)/σ. Así se pasa a la normal estándar N(0,1) para usar la tabla.","topic":"Distribuciones","difficulty":1,"fromOrientaciones":true},{"id":"mat-090","front":"¿Qué es la aproximación de la binomial a la normal?","back":"Consiste en sustituir una binomial por una normal con media np y desviación típica √(npq), cuando n es grande y np, nq son suficientes.","topic":"Distribuciones","difficulty":3,"fromOrientaciones":true},{"id":"mat-091","front":"¿Para qué sirve la corrección de Yates en la aproximación binomial-normal?","back":"Sirve para ajustar el paso de variable discreta a continua. Se suma o resta 0,5 en los extremos del intervalo.","topic":"Distribuciones","difficulty":3,"fromOrientaciones":true},{"id":"mat-092","front":"¿Cómo se calcula P(X>a) en una distribución normal?","back":"Se tipifica a: z=(a-μ)/σ y luego se usa la tabla como P(X>a)=P(Z>z)=1-P(Z≤z).","topic":"Distribuciones","difficulty":2,"fromOrientaciones":true},{"id":"mat-093","front":"¿Cómo se calcula la probabilidad de que una normal esté entre dos valores?","back":"Se tipifican ambos extremos y se resta: P(a<X<b)=P(Z<z2)-P(Z<z1).","topic":"Distribuciones","difficulty":2,"fromOrientaciones":true},{"id":"mat-094","front":"¿Qué significa modelizar un fenómeno con una distribución binomial?","back":"Que se interpreta como una sucesión de ensayos independientes con dos resultados posibles y probabilidad de éxito constante.","topic":"Distribuciones","difficulty":2,"fromOrientaciones":true},{"id":"mat-095","front":"¿Qué significa modelizar un fenómeno con una distribución normal?","back":"Que la variable continua se concentra alrededor de una media y presenta simetría. Es habitual en medidas físicas y biológicas.","topic":"Distribuciones","difficulty":2,"fromOrientaciones":true},{"id":"mat-096","front":"¿Qué es la probabilidad como medida clásica de la incertidumbre?","back":"Es la razón entre casos favorables y casos posibles, cuando todos son equiprobables.","topic":"Probabilidad","difficulty":1,"fromOrientaciones":true},{"id":"mat-097","front":"¿Qué es la interpretación frecuentista de la probabilidad?","back":"Entiende la probabilidad como el valor al que tiende la frecuencia relativa de un suceso al repetir muchas veces el experimento.","topic":"Probabilidad","difficulty":1,"fromOrientaciones":true},{"id":"mat-098","front":"¿Qué es la interpretación subjetiva de la probabilidad?","back":"Es el grado de creencia razonable que se asigna a un suceso con la información disponible.","topic":"Probabilidad","difficulty":1,"fromOrientaciones":true},{"id":"mat-099","front":"¿Cómo se usa un diagrama de árbol en un experimento compuesto?","back":"Se representan etapas sucesivas del experimento, multiplicando probabilidades a lo largo de cada rama y sumando ramas compatibles.","topic":"Probabilidad","difficulty":2,"fromOrientaciones":true},{"id":"mat-100","front":"¿Cómo ayuda una tabla de contingencia a resolver problemas de probabilidad?","back":"Organiza los datos por categorías y permite leer fácilmente probabilidades conjuntas, marginales y condicionadas.","topic":"Probabilidad","difficulty":2,"fromOrientaciones":true},{"id":"mat-101","front":"¿Qué expresa la unión de dos sucesos A y B?","back":"El suceso A∪B ocurre si ocurre A, o B, o ambos a la vez.","topic":"Probabilidad","difficulty":1,"fromOrientaciones":true},{"id":"mat-102","front":"¿Qué expresa la intersección de dos sucesos A y B?","back":"El suceso A∩B ocurre solo si ocurren simultáneamente A y B.","topic":"Probabilidad","difficulty":1,"fromOrientaciones":true},{"id":"mat-103","front":"¿Qué es el suceso complementario de A?","back":"Es el suceso de que A no ocurra. Se denota Aᶜ y cumple P(Aᶜ)=1-P(A).","topic":"Probabilidad","difficulty":1,"fromOrientaciones":true},{"id":"mat-104","front":"¿Qué dice la fórmula de la unión de dos sucesos?","back":"P(A∪B)=P(A)+P(B)-P(A∩B). Evita contar dos veces la intersección.","topic":"Probabilidad","difficulty":2,"fromOrientaciones":true},{"id":"mat-105","front":"¿Qué establecen los axiomas de Kolmogórov?","back":"Que toda probabilidad es no negativa, P(Ω)=1 y la probabilidad de sucesos incompatibles se suma.","topic":"Probabilidad","difficulty":2,"fromOrientaciones":true},{"id":"mat-106","front":"¿Qué significa que dos sucesos sean incompatibles?","back":"Que no pueden ocurrir a la vez. Entonces A∩B=∅ y P(A∩B)=0.","topic":"Probabilidad","difficulty":1,"fromOrientaciones":true},{"id":"mat-107","front":"¿Cómo se calcula la probabilidad de un suceso imposible y de un suceso seguro?","back":"El suceso imposible tiene probabilidad 0 y el suceso seguro tiene probabilidad 1.","topic":"Probabilidad","difficulty":1,"fromOrientaciones":true},{"id":"mat-108","front":"¿Qué significa actualizar una probabilidad tras una observación?","back":"Que se revisa la probabilidad inicial usando la información nueva, normalmente mediante probabilidad condicionada o Bayes.","topic":"Probabilidad","difficulty":2,"fromOrientaciones":true},{"id":"mat-109","front":"¿Qué es una función definida a trozos?","back":"Es una función que usa expresiones distintas según el intervalo de x considerado.","topic":"Funciones","difficulty":1,"fromOrientaciones":true},{"id":"mat-110","front":"¿Cómo se determina el dominio de derivabilidad de una función?","back":"Se estudian los puntos donde la función no está definida, no es continua o presenta esquinas, puntas o tangentes verticales.","topic":"Cálculo diferencial","difficulty":2,"fromOrientaciones":true},{"id":"mat-111","front":"¿Qué información se puede obtener de la gráfica de una función?","back":"Dominio, continuidad, límites, asíntotas, crecimiento, extremos, concavidad y puntos de corte, entre otros.","topic":"Representación de funciones","difficulty":1,"fromOrientaciones":true},{"id":"mat-112","front":"¿Qué información se puede obtener de la gráfica de la derivada f'(x)?","back":"Los intervalos de crecimiento y decrecimiento de f, y los puntos donde f puede tener extremos relativos.","topic":"Representación de funciones","difficulty":2,"fromOrientaciones":true},{"id":"mat-113","front":"¿Cómo se detectan los intervalos donde una función crece a partir de la gráfica de f'?","back":"Donde f'(x) está por encima del eje X, es decir, donde f'(x)>0.","topic":"Representación de funciones","difficulty":2,"fromOrientaciones":true},{"id":"mat-114","front":"¿Cómo se detectan los intervalos donde una función decrece a partir de la gráfica de f'?","back":"Donde f'(x) está por debajo del eje X, es decir, donde f'(x)<0.","topic":"Representación de funciones","difficulty":2,"fromOrientaciones":true},{"id":"mat-115","front":"¿Qué indica que f'(a)=0 en la gráfica de la derivada?","back":"Que en x=a la función f tiene tangente horizontal y ese punto es candidato a máximo, mínimo o punto de inflexión horizontal.","topic":"Cálculo diferencial","difficulty":2,"fromOrientaciones":true},{"id":"mat-116","front":"¿Cómo se interpreta geométricamente la derivada en un punto?","back":"Como la pendiente de la recta tangente a la gráfica de la función en ese punto.","topic":"Cálculo diferencial","difficulty":1,"fromOrientaciones":true},{"id":"mat-117","front":"¿Qué pasos básicos hay que seguir para estudiar la continuidad de una función a trozos en x=a?","back":"Calcular el límite por la izquierda, el límite por la derecha y el valor f(a), y comprobar si coinciden.","topic":"Límites y continuidad","difficulty":2,"fromOrientaciones":true},{"id":"mat-118","front":"¿Qué pasos básicos hay que seguir para estudiar la derivabilidad de una función a trozos en x=a?","back":"Primero comprobar continuidad en a; después calcular derivada lateral izquierda y derecha y ver si coinciden.","topic":"Cálculo diferencial","difficulty":2,"fromOrientaciones":true},{"id":"mat-119","front":"¿Qué son los extremos absolutos de una función en un intervalo?","back":"Son el mayor y el menor valor que toma la función en ese intervalo, ya sea en puntos críticos o en extremos del intervalo.","topic":"Optimización","difficulty":2,"fromOrientaciones":true},{"id":"mat-120","front":"¿Cómo se buscan máximos y mínimos absolutos en un intervalo cerrado?","back":"Se evalúa la función en puntos críticos interiores y en los extremos del intervalo, y se comparan los valores.","topic":"Optimización","difficulty":2,"fromOrientaciones":true},{"id":"mat-121","front":"¿Qué significa interpretar el resultado de un problema de optimización dentro del contexto?","back":"Que no basta con obtener un número: hay que decidir si tiene sentido real, con sus unidades y restricciones del problema.","topic":"Optimización","difficulty":2,"fromOrientaciones":true},{"id":"mat-122","front":"¿Cómo se calcula el valor medio de una función f en [a,b]?","back":"Se usa f_media = 1/(b-a) · ∫[a,b] f(x)dx.","topic":"Cálculo integral","difficulty":2,"fromOrientaciones":true},{"id":"mat-123","front":"¿Qué significa interpretar la integral definida como área bajo una curva?","back":"Que mide el área con signo entre la gráfica y el eje X en el intervalo considerado.","topic":"Cálculo integral","difficulty":1,"fromOrientaciones":true},{"id":"mat-124","front":"¿Qué ocurre con la integral definida si se cambia el orden de los límites?","back":"Cambia de signo: ∫[a,b]f(x)dx = -∫[b,a]f(x)dx.","topic":"Cálculo integral","difficulty":2,"fromOrientaciones":true},{"id":"mat-125","front":"¿Cómo se calcula una primitiva inmediata de xⁿ con n≠-1?","back":"∫xⁿdx = xⁿ⁺¹/(n+1) + C. Es una de las reglas básicas de integración.","topic":"Cálculo integral","difficulty":1,"fromOrientaciones":true},{"id":"mat-126","front":"¿Cómo se calcula una primitiva inmediata de 1/x?","back":"∫(1/x)dx = ln|x| + C. Hay que usar valor absoluto.","topic":"Cálculo integral","difficulty":1,"fromOrientaciones":true},{"id":"mat-127","front":"¿Cómo se calcula una primitiva inmediata de eˣ?","back":"∫eˣdx = eˣ + C. La exponencial natural es su propia derivada y su propia primitiva.","topic":"Cálculo integral","difficulty":1,"fromOrientaciones":true},{"id":"mat-128","front":"¿Cómo se calcula una primitiva inmediata de sen(x)?","back":"∫sen(x)dx = -cos(x) + C. Conviene recordar el signo.","topic":"Cálculo integral","difficulty":1,"fromOrientaciones":true},{"id":"mat-129","front":"¿Cómo se calcula una primitiva inmediata de cos(x)?","back":"∫cos(x)dx = sen(x) + C.","topic":"Cálculo integral","difficulty":1,"fromOrientaciones":true},{"id":"mat-130","front":"¿Cómo se integran funciones racionales cuando el denominador tiene raíces reales simples?","back":"Normalmente se descomponen en fracciones simples y se integra cada término por separado.","topic":"Cálculo integral","difficulty":3,"fromOrientaciones":true},{"id":"mat-131","front":"¿Qué idea básica hay detrás de la descomposición en fracciones simples?","back":"Expresar una función racional como suma de términos más sencillos, como A/(x-a), para poder integrar fácilmente.","topic":"Cálculo integral","difficulty":3,"fromOrientaciones":true},{"id":"mat-132","front":"¿Qué representa la longitud de un vector en el espacio?","back":"Su módulo: |v|=√(a²+b²+c²) si v=(a,b,c). Mide la distancia desde el origen hasta el extremo del vector.","topic":"Vectores y geometría","difficulty":1,"fromOrientaciones":true},{"id":"mat-133","front":"¿Cómo se expresa un vector como combinación lineal de otros?","back":"Buscando escalares λ, μ, ... tales que v = λv1 + μv2 + ... Si existe, queda generado por esos vectores.","topic":"Álgebra lineal","difficulty":2,"fromOrientaciones":true},{"id":"mat-134","front":"¿Qué significa que tres vectores del espacio sean linealmente dependientes?","back":"Que uno de ellos puede escribirse como combinación lineal de los otros dos. Geométricamente, quedan en un mismo plano.","topic":"Álgebra lineal","difficulty":2,"fromOrientaciones":true},{"id":"mat-135","front":"¿Cómo se puede interpretar un problema de posiciones relativas de rectas y planos como un sistema lineal?","back":"Igualando sus ecuaciones y estudiando si el sistema tiene solución única, infinitas o ninguna. Eso indica intersección, coincidencia o paralelismo.","topic":"Geometría del espacio","difficulty":3,"fromOrientaciones":true},{"id":"mat-136","front":"¿Qué condición deben cumplir dos rectas para ser paralelas?","back":"Sus vectores directores deben ser proporcionales. Si además comparten un punto, entonces coinciden.","topic":"Geometría del espacio","difficulty":1,"fromOrientaciones":true},{"id":"mat-137","front":"¿Qué condición debe cumplir una recta para ser perpendicular a un plano?","back":"Su vector director debe ser paralelo al vector normal del plano.","topic":"Geometría métrica","difficulty":2,"fromOrientaciones":true},{"id":"mat-138","front":"¿Qué condición deben cumplir una recta y un plano para ser paralelos?","back":"El vector director de la recta debe ser perpendicular al vector normal del plano.","topic":"Geometría métrica","difficulty":2,"fromOrientaciones":true},{"id":"mat-139","front":"¿Qué significa proyectar ortogonalmente una recta sobre un plano?","back":"Obtener la recta formada por las proyecciones ortogonales de sus puntos sobre el plano.","topic":"Geometría del espacio","difficulty":3,"fromOrientaciones":true},{"id":"mat-140","front":"¿Qué es el punto simétrico de un punto respecto de un plano?","back":"Es el punto situado al otro lado del plano a la misma distancia, de modo que el plano es mediador del segmento que los une.","topic":"Geometría del espacio","difficulty":2,"fromOrientaciones":true},{"id":"mat-141","front":"¿Qué es el punto simétrico de un punto respecto de otro punto?","back":"Es el punto que deja al punto dado como punto medio del segmento que los une.","topic":"Geometría del espacio","difficulty":1,"fromOrientaciones":true},{"id":"mat-142","front":"¿Qué significa que una recta sea simétrica respecto de un plano?","back":"Que todos sus puntos se reflejan respecto del plano, generando otra recta imagen.","topic":"Geometría del espacio","difficulty":3,"fromOrientaciones":true},{"id":"mat-143","front":"¿Cómo se calcula el volumen de un paralelepípedo a partir de tres vectores?","back":"Con el valor absoluto del producto mixto: V=|u·(v×w)|.","topic":"Geometría del espacio","difficulty":2,"fromOrientaciones":true},{"id":"mat-144","front":"¿Cómo se distingue una matriz fila de una matriz columna?","back":"La matriz fila tiene una sola fila; la matriz columna tiene una sola columna.","topic":"Álgebra lineal","difficulty":1,"fromOrientaciones":true},{"id":"mat-145","front":"¿Qué es una matriz diagonal?","back":"Es una matriz cuadrada cuyos elementos fuera de la diagonal principal son 0.","topic":"Álgebra lineal","difficulty":1,"fromOrientaciones":true},{"id":"mat-146","front":"¿Qué es una matriz triangular?","back":"Es una matriz cuadrada con todos los elementos por encima o por debajo de la diagonal principal iguales a 0.","topic":"Álgebra lineal","difficulty":1,"fromOrientaciones":true},{"id":"mat-147","front":"¿Qué es una matriz nula?","back":"Es la matriz cuyos elementos son todos 0. Se denota O.","topic":"Álgebra lineal","difficulty":1,"fromOrientaciones":true},{"id":"mat-148","front":"¿Qué propiedad útil tiene el determinante de una matriz triangular?","back":"Su determinante es el producto de los elementos de la diagonal principal.","topic":"Álgebra lineal","difficulty":2,"fromOrientaciones":true},{"id":"mat-149","front":"¿Cómo se detecta rápidamente si una matriz cuadrada no puede ser invertible usando su rango?","back":"Si su rango es menor que su orden, no es invertible. Para serlo debe tener rango máximo.","topic":"Álgebra lineal","difficulty":2,"fromOrientaciones":true},{"id":"mat-150","front":"¿Qué representa el rango de una matriz en términos de sus filas?","back":"El número máximo de filas linealmente independientes que contiene.","topic":"Álgebra lineal","difficulty":1,"fromOrientaciones":true},{"id":"mat-151","front":"¿Cómo se discute un sistema lineal dependiente de un parámetro?","back":"Se calculan los valores del parámetro que cambian el rango o el determinante, y luego se estudia cada caso por separado.","topic":"Sistemas lineales","difficulty":3,"fromOrientaciones":true},{"id":"mat-152","front":"¿Qué significa que una función sea periódica?","back":"Que existe un número T>0 tal que f(x+T)=f(x) para todo x del dominio. T es su período.","topic":"Funciones","difficulty":1,"fromOrientaciones":true},{"id":"mat-153","front":"¿Cómo se hallan los cortes con los ejes de una función y=f(x)?","back":"Con el eje Y se toma x=0; con el eje X se resuelve f(x)=0.","topic":"Representación de funciones","difficulty":1,"fromOrientaciones":true},{"id":"mat-154","front":"¿Qué significa esbozar la gráfica de una función de manera aproximada?","back":"Representarla con sus rasgos principales, sin necesidad de dibujar cada punto exacto, usando su estudio analítico.","topic":"Representación de funciones","difficulty":1,"fromOrientaciones":true},{"id":"mat-155","front":"¿Qué utilidad tiene conocer las propiedades algebraicas de las funciones continuas?","back":"Permite deducir continuidad en sumas, productos, cocientes y composiciones sin recalcular límites desde cero.","topic":"Límites y continuidad","difficulty":2,"fromOrientaciones":true},{"id":"mat-156","front":"¿Qué tipo de situaciones reales pueden modelizarse con funciones para estudiar límites y derivadas?","back":"Crecimientos, costes, velocidades, concentraciones, temperaturas o beneficios, entre otras magnitudes que cambian con una variable.","topic":"Modelización","difficulty":1,"fromOrientaciones":true},{"id":"mat-157","front":"¿Qué significa resolver un problema de superficie plana mediante integrales?","back":"Traducir la región geométrica a una diferencia de funciones e integrar en el intervalo adecuado.","topic":"Cálculo integral","difficulty":2,"fromOrientaciones":true},{"id":"mat-158","front":"¿Qué significa resolver un problema de volumen de revolución con integrales?","back":"Expresar el volumen del sólido generado al girar una región plana alrededor de un eje mediante una integral.","topic":"Cálculo integral","difficulty":2,"fromOrientaciones":true},{"id":"mat-159","front":"¿Qué es una decisión en condiciones de incertidumbre en probabilidad?","back":"Es elegir entre opciones cuando no se conoce con certeza el resultado, usando probabilidades para valorar riesgos.","topic":"Probabilidad","difficulty":2,"fromOrientaciones":true},{"id":"mat-160","front":"¿Qué significa resolver problemas de probabilidad en contexto real?","back":"Traducir una situación concreta al lenguaje probabilístico, identificar sucesos y aplicar la herramienta adecuada con interpretación final.","topic":"Probabilidad","difficulty":2,"fromOrientaciones":true}]`),i={subject:e,flashcards:a};export{i as default,a as flashcards,e as subject};
